          .footer-floating-kang {
              position: fixed;
              bottom: 18px;
              left: 50%;
              transform: translateX(-50%);
              width: 100%;
              max-width: 1500px;
              display: flex;
              gap: 14px;
              padding: 16px 22px;
              box-shadow: 0 0 30px transparent;
              backdrop-filter: blur(10px);
              border-radius: 20px;
              border: 2px solid rgb(0 0 0 / 50%);
              box-shadow: 0 0 30px rgb(0 0 0 / 60%);
              z-index: 999;
          }
 
          /* BUTTON BASE (EQUAL SIZE) */
          .footer-btn-kang {
              flex: 1;
              min-width: 0;
              display: flex;
              align-items: center;
              justify-content: center;
              gap: 8px;
              padding: 12px 10px;
              font-size: 14px;
              font-weight: bold;
              color: #ffffff;
              background: #F2DB05;
              border-radius: 32px;
              border: 2px solid #000000;
              cursor: pointer;
              transition: all 0.3s ease;
              box-shadow: 0 0 14px rgb(55 255 255 / 60%);
              animation: floatUpDown 3s ease-in-out infinite;
              text-decoration: none;
              user-select: none;
              white-space: nowrap;
          }
          /* ICON */
          .footer-btn-kang img {
              width: 18px;
              height: 18px;
              flex-shrink: 0;
              filter: drop-shadow(0 0 5px rgb(255 177 0 / 80%));
          }
          /* FLOAT DELAY */
          .footer-btn-kang.login {
              animation-delay: 0.3s;
          }
          .footer-btn-kang.daftar {
              animation-delay: 0.6s;
          }
          .footer-btn-kang.link {
              animation-delay: 0.9s;
          }
          .footer-btn-kang.chat {
              animation-delay: 1.2s;
          }
          /* HOVER GLOW */
          .footer-btn-kang:hover {
              background: gold;
              box-shadow:
                  0 0 15px #F2DB05,
                  0 0 30px #F2DB05,
                  0 0 50px #ff7e4d;
              transform: translateY(-6px) scale(1.05);
          }
          /* ACTIVE GOLD */
          .footer-btn-kang:active {
              background: linear-gradient(135deg, #ffd700, #ffb800);
              color: #000;
              border-color: #ffd700;
              box-shadow:
                  0 0 18px #ffd700,
                  0 0 35px #ffcc00;
          }
          /* FLOAT ANIMATION */
          @keyframes floatUpDown {
              0% {
                  transform: translateY(0);
              }
              50% {
                  transform: translateY(-8px);
              }
              100% {
                  transform: translateY(0);
              }
          }
          /* RESPONSIVE */
          @media (max-width: 1024px) {
              .footer-floating-kang {
